/* ==== 塔罗 LLM 配置面板（独立注入，不依赖 React） ==== */
(function(){
  var KEY="tarot_llm_config_v1";
  var DEF={enabled:true,thinkingEnabled:false,provider:"openai_compatible",baseUrl:"/api/bxk/private_chat",model:"bxk-private-chat-1114",apiKey:"builtin",temperature:0.7,timeoutMs:119999,privateChat:{endpoint:"/api/bxk/private_chat",kid:"1114",chatMod:"bot"}};
  function load(){try{var s=localStorage.getItem(KEY);if(s){var p=JSON.parse(s);return Object.assign({},DEF,p,{privateChat:Object.assign({},DEF.privateChat,(p&&p.privateChat)||{})});}}catch(e){}return JSON.parse(JSON.stringify(DEF));}
  function save(c){localStorage.setItem(KEY,JSON.stringify(c));}
  function el2(tag,attrs,txt){var e=document.createElement(tag);if(attrs)for(var k in attrs)e.setAttribute(k,attrs[k]);if(txt!=null)e.textContent=txt;return e;}
  function placeBtn(btn){
    var header=document.querySelector(".home-search-header");
    if(header&&btn.parentNode!==header){
      var hist=header.querySelector(".home-history-link");
      btn.className=hist?hist.className:"home-history-link";
      btn.removeAttribute("style");
      if(hist&&hist.nextSibling)header.insertBefore(btn,hist.nextSibling);else header.appendChild(btn);
    }else if(!header&&!btn.parentNode){
      document.body.appendChild(btn);
      btn.style.cssText="position:fixed;right:16px;top:16px;z-index:99999;padding:8px 12px;border-radius:8px;border:none;background:rgba(30,20,50,.85);color:#e8dcff;font-size:13px;cursor:pointer";
    }
  }
  function build(){
    if(document.getElementById("tarot-cfg-btn"))return;
    var btn=el2("button",{id:"tarot-cfg-btn",type:"button",title:"LLM 配置","aria-label":"LLM 配置"},"⚙ 配置");
    var mask=el2("div",{id:"tarot-cfg-mask"});
    mask.style.cssText="position:fixed;inset:0;z-index:99998;background:rgba(0,0,0,.55);display:none;align-items:center;justify-content:center;padding:16px";
    var box=el2("div");
    box.style.cssText="background:#1b1430;color:#eee;max-width:440px;width:100%;max-height:88vh;overflow:auto;border-radius:14px;padding:20px 22px;box-shadow:0 10px 40px rgba(0,0,0,.6);font-size:14px;line-height:1.6";
    box.appendChild(el2("h2",null,"LLM 配置")).style.cssText="margin:0 0 14px;font-size:18px;color:#c9b6ff";
    var fields=[
      ["enabled","启用 LLM 解析","checkbox"],
      ["thinkingEnabled","开启深度思考","checkbox"],
      ["provider","provider","text"],
      ["baseUrl","接口地址 baseUrl","text"],
      ["model","模型 model","text"],
      ["apiKey","鉴权 apiKey","text"],
      ["temperature","temperature (0-1)","number"],
      ["timeoutMs","超时 timeoutMs (毫秒)","number"],
      ["pc_endpoint","私有接口 endpoint","text"],
      ["pc_kid","私有接口 kid","text"],
      ["pc_chatMod","私有接口 chat_mod","text"]
    ];
    var cur=load();var inputs={};
    fields.forEach(function(f){
      var wrap=el2("label");wrap.style.cssText="display:flex;flex-direction:column;gap:4px;margin-bottom:12px";
      var lab=el2("span",null,f[1]);lab.style.cssText="color:#b0a0d0;font-size:12px";
      wrap.appendChild(lab);
      var inp;
      var val=f[0].indexOf("pc_")===0?cur.privateChat[f[0].slice(3)]:cur[f[0]];
      if(f[2]==="checkbox"){inp=el2("input",{type:"checkbox"});inp.checked=!!val;inp.style.cssText="width:20px;height:20px";}
      else{inp=el2("input",{type:f[2]});inp.value=val==null?"":val;inp.style.cssText="background:#0f0a1e;border:1px solid #453667;border-radius:6px;color:#eee;padding:7px 9px;font-size:13px";}
      inputs[f[0]]=inp;wrap.appendChild(inp);box.appendChild(wrap);
    });
    var row=el2("div");row.style.cssText="display:flex;gap:10px;margin-top:16px";
    var saveBtn=el2("button",null,"保存并生效");
    saveBtn.style.cssText="flex:1;background:#6d4fd0;color:#fff;border:none;border-radius:8px;padding:10px;cursor:pointer;font-size:14px";
    var resetBtn=el2("button",null,"恢复默认");
    resetBtn.style.cssText="background:#3a2f55;color:#ddd;border:none;border-radius:8px;padding:10px 14px;cursor:pointer;font-size:14px";
    var closeBtn=el2("button",null,"关闭");
    closeBtn.style.cssText="background:#2a2140;color:#bbb;border:none;border-radius:8px;padding:10px 14px;cursor:pointer;font-size:14px";
    row.appendChild(saveBtn);row.appendChild(resetBtn);row.appendChild(closeBtn);box.appendChild(row);
    var tip=el2("p",null,"保存后刷新页面或重新占卜即可生效。");tip.style.cssText="color:#8878a8;font-size:12px;margin:12px 0 0";box.appendChild(tip);
    mask.appendChild(box);document.body.appendChild(mask);
    placeBtn(btn);
    var mo=new MutationObserver(function(){if(!document.body.contains(btn)||btn.parentNode===document.body){}placeBtn(btn);});
    mo.observe(document.body,{childList:true,subtree:true});
    function open(){var c=load();fields.forEach(function(f){var v=f[0].indexOf("pc_")===0?c.privateChat[f[0].slice(3)]:c[f[0]];if(f[2]==="checkbox")inputs[f[0]].checked=!!v;else inputs[f[0]].value=v==null?"":v;});mask.style.display="flex";}
    function close(){mask.style.display="none";}
    btn.onclick=open;closeBtn.onclick=close;
    mask.onclick=function(e){if(e.target===mask)close();};
    saveBtn.onclick=function(){
      var c=JSON.parse(JSON.stringify(DEF));
      c.enabled=inputs.enabled.checked;c.thinkingEnabled=inputs.thinkingEnabled.checked;
      c.provider=inputs.provider.value.trim()||DEF.provider;
      c.baseUrl=inputs.baseUrl.value.trim()||DEF.baseUrl;
      c.model=inputs.model.value.trim()||DEF.model;
      c.apiKey=inputs.apiKey.value.trim()||DEF.apiKey;
      var tp=parseFloat(inputs.temperature.value);c.temperature=isNaN(tp)?DEF.temperature:tp;
      var to=parseInt(inputs.timeoutMs.value,10);c.timeoutMs=isNaN(to)?DEF.timeoutMs:to;
      c.privateChat.endpoint=inputs.pc_endpoint.value.trim()||DEF.privateChat.endpoint;
      c.privateChat.kid=inputs.pc_kid.value.trim()||DEF.privateChat.kid;
      c.privateChat.chatMod=inputs.pc_chatMod.value.trim()||DEF.privateChat.chatMod;
      save(c);saveBtn.textContent="已保存 ✓";setTimeout(function(){saveBtn.textContent="保存并生效";},1500);
    };
    resetBtn.onclick=function(){localStorage.removeItem(KEY);open();resetBtn.textContent="已恢复 ✓";setTimeout(function(){resetBtn.textContent="恢复默认";},1500);};
  }
  if(document.readyState==="loading")document.addEventListener("DOMContentLoaded",build);else build();
})();
